field.text:
checkpoint("cooking_for_five", "gather", { done: true })

var knowledge = loadKnowledge({
  "cooking": {
    "cuisine": {
      "type": {
        "japanese": true
      }
    },
    "dietary": {
      "restriction": {
        "vegetarian": true
      }
    },
    "technique": {
      "method": {
        "braise": true
      }
    }
  },
  "nutrition": {
    "macronutrients": {
      "type": {
        "protein": true,
        "carbohydrates": true,
        "fats": true
      }
    },
    "meal-planning": {
      "strategy": {
        "plate-method": true
      }
    }
  }
})

await stop(knowledge)

checkpoint("cooking_for_five", "load_knowledge", { loaded: true })
// Create a base recipe for Japanese braised tofu (for 2 servings, then scale to 5) var baseIngredients = [ "200g firm tofu", "1 tbsp soy sauce", "1 tbsp mirin", "1 tbsp sake", "1 cup dashi stock", "1 small onion, quartered", "2 carrots, sliced", "2 shiitake mushrooms", "1 tbsp vegetable oil", "1 tsp sugar", "Green onions for garnish" ]
var baseRecipe = { name: "Japanese Braised Tofu (Nikujaga-style)", cuisine: "Japanese", method: "Braise", servings: 2, time: 45, // minutes ingredients: baseIngredients, steps: [ "Press tofu for 15 minutes to remove excess water", "Heat oil in a Dutch oven over medium-high heat", "Sear tofu cubes until golden brown on all sides", "Remove tofu and sauté onions and carrots until softened", "Add mushrooms and cook for 2 more minutes", "Return tofu to pot and add dashi, soy sauce, mirin, sake, and sugar", "Bring to a simmer, then reduce heat to low", "Cover and braise for 25-30 minutes until vegetables are tender", "Remove lid and increase heat to reduce liquid slightly", "Garnish with green onions and serve" ] }
// Scale recipe for 5 servings (2.5x multiplier) var scaledIngredients = scaleIngredients(baseIngredients, 2.5) await stop(scaledIngredients)

checkpoint("cooking_for_five", "scale_recipe", { scaled: true })

// Estimate nutrition for the scaled recipe (assuming standard nutrition values for these ingredients)
var estimatedNutrition = estimateCalories(
  80,  // protein grams (tofu + mushrooms)
  45,  // carbs grams (carrots, onions, mirin, sugar)
  15   // fat grams (oil, tofu)
)
await stop(estimatedNutrition)

checkpoint("cooking_for_five", "estimate_nutrition", { calculated: true })

// Build grocery list for this recipe
var groceryList = buildGroceryList([{
  name: baseRecipe.name,
  ingredients: scaledIngredients
}])
await stop(groceryList)

checkpoint("cooking_for_five", "build_grocery", { built: true })

// Format the cooking time
var formattedTime = formatTime(baseRecipe.time)
await stop(formattedTime)

checkpoint("cooking_for_five", "gather", { done: true })

